@startuml
skinparam classAttributeIconSize 0
hide circle

class Artist {
    id : VARCHAR <<PK>>
    name : VARCHAR 
    instagram : VARCHAR 
    facebook : VARCHAR 
    twitter : VARCHAR 
    wikipedia : VARCHAR 
    bio : TEXT 
}

class Album {
    id : VARCHAR <<PK>>
    title : VARCHAR 
    release : VARCHAR 
    image : VARCHAR 
}

class Song {
    id : VARCHAR <<PK>>
    album_id : VARCHAR <<FK>>
    title : VARCHAR 
    duration : INT 
}

class PlaylistCategory {
    id : VARCHAR <<PK>>
    name : VARCHAR 
    image : VARCHAR 
    icon : VARCHAR 
}

class PodcastCategory {
    id : VARCHAR <<PK>>
    name : VARCHAR 
    image : VARCHAR 
    icon : VARCHAR 
}

class User {

}

class Concert {

}

Artist --|> "1" Album : creates > *
Album ..* "many" Song 

PlaylistCategory <|-- "*" Playlist  
PodcastCategory <|-- "*" Podcast  

@enduml
